from math import gcd,lcm,isqrt

def primes(n):
 r=[];d=2
 while d*d<=n:
  if n%d==0:
   r.append(d)
   while n%d==0:n//=d
  d+=1
 if n>1:r.append(n)
 return r

def upd(D,x):
 E={lcm(d,p) for d in D for p in primes(x)}
 return sorted(e for e in E if not any(f<e and e%f==0 for f in E))
def run(a,N=1000):
 D=primes(a);s=[a];lastchange=0
 for k in range(1,N):
  x=min(d*(a//d+1) for d in D)
  a=x;s.append(a)
  E=upd(D,a)
  if E!=D:lastchange=k
  D=E
